// Format approval digest summary for notification.
// Hardened: wraps in try/catch to prevent 'Unknown error' crashes on bad API responses.
try {
  const input = $input.item || $input.first();
  if (!input || !input.json) {
    return [{ json: { message: 'Approval digest unavailable — no response.', error: 'no_input' } }];
  }
  const digest = input.json.digest || input.json;
  const lines = [
    `📋 Daily Approval Queue — ${new Date().toLocaleDateString()}`,
    `Total pending: ${digest.totalPending || 0}`,
    `Recommended: ${digest.recommendedCount || 0}`,
    `High fit (70+): ${digest.highFitCount || 0}`,
  ];
  if ((digest.topOpportunities || []).length > 0) {
    lines.push('\nTop roles:');
    digest.topOpportunities.slice(0, 5).forEach(o => {
      lines.push(`  • ${o.fitScore} — ${o.title} @ ${o.company}${o.recommended ? ' ✓' : ''}`);
    });
  }
  return [{ json: { message: lines.join('\n'), digest } }];
} catch (err) {
  console.error('[approval-digest] Format error:', err.message || String(err));
  return [{ json: { message: 'Approval digest format error — see n8n logs.', error: err.message || String(err) } }];
}
